use serenity::prelude::*;

#[tokio::main]
async fn main() {
    // Read the bot token from the DISCORD_TOKEN env var. Set it in a .env
    // file in this folder (the kern host injects .env into the process).
    let token = std::env::var("DISCORD_TOKEN").expect("missing DISCORD_TOKEN env var — add it to .env");
    println!("discord bot starting…");
    // TODO: build and start your serenity client here.
    let _ = token;
}
